function ComponentCard({item}: {item: ComponentItem}): ReactElement {
  return (
    <a
      href={item.href}
      className={`foundation-overview-card${item.disabled ? ' foundation-overview-card--disabled' : ''}`}
    >
      <div className="foundation-overview-card__image">
        {item.previewNode ?? (item.preview && (
          <img
            src={`/img/previews/${item.preview}`}
            alt={`${item.name} component thumbnail`}
            width="100%"
            height="100%"
          />
        ))}
      </div>
      <div className="foundation-overview-card__body">
        <span>{item.name}</span>
      </div>
    </a>
  );
}

export default function ComponentsOverviewContent(): ReactElement {
  return (
    <div className="button-guide-page components-overview">
      <header className="button-guide-header">
        <h1>Components</h1>
        <p>사용자 인터페이스를 구성하는 재사용 가능한 UI 요소입니다. 컴포넌트를 활용하여 제품 전반의 일관된 사용자 경험을 제공합니다.</p>
        <svg width="100%" height="1" viewBox="0 0 900 1" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true" className="components-overview__header-divider">
          <rect width="900" height="1" fill="var(--sol-border-solid-variant)"/>
        </svg>
      </header>

      <div className="components-overview__sections">
        {categories.map((category) => (
          <section key={category.label} className="button-guide-section">
            <h2 className={category.tbd ? 'components-overview-heading--tbd' : undefined}>
              {category.label}
              {category.tbd && <span className="components-overview-tbd-badge">TBD</span>}
            </h2>
            {!category.tbd && (
              <div className="components-overview__grid">
                {category.items.map((item) => (
                  <ComponentCard key={item.name} item={item} />
                ))}
              </div>
            )}
          </section>
        ))}
      </div>
    </div>
  );
}
